function UserCard({ name, role, isActive }) {
  return (
    <div className="card">
      <h2>{name}</h2>
      <p>{role}</p>
      <span className={isActive ? 'online' : 'offline'}>
        {isActive ? 'Active' : 'Away'}
      </span>
    </div>
  );
}

function App() {
  const users = [
    { name: 'Alice', role: 'Dev', isActive: true },
    { name: 'Bob', role: 'Designer', isActive: false }
  ];
  return (
    <div>
      <h1>Team</h1>
      {users.map(u => <UserCard key={u.name} {...u} />)}
    </div>
  );
}
console.log('React components render a team list');
